import{_ as d,o as a,c as r,a4 as e}from"./chunks/framework.ChErgFjV.js";const u=JSON.parse('{"title":"《人性话术大师》读书笔记","description":"","frontmatter":{},"headers":[],"relativePath":"study/reading-notes/20260713-《人性话术大师》读书笔记.md","filePath":"study/reading-notes/20260713-《人性话术大师》读书笔记.md","lastUpdated":1783931283000}'),o={name:"study/reading-notes/20260713-《人性话术大师》读书笔记.md"};function l(h,t,i,n,s,p){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="《人性话术大师》读书笔记" tabindex="-1">《人性话术大师》读书笔记 <a class="header-anchor" href="#《人性话术大师》读书笔记" aria-label="Permalink to &quot;《人性话术大师》读书笔记&quot;">​</a></h1><blockquote><p>书名：人性话术大师 作者：阿宝 分类：🧠 认知心理学 阅读日期：2026年7月13日 书籍页数：145页</p></blockquote><hr><h2 id="一、核心观点" tabindex="-1">一、核心观点 <a class="header-anchor" href="#一、核心观点" aria-label="Permalink to &quot;一、核心观点&quot;">​</a></h2><h3 id="_1-语言系统决定命运" tabindex="-1">1. 语言系统决定命运 <a class="header-anchor" href="#_1-语言系统决定命运" aria-label="Permalink to &quot;1. 语言系统决定命运&quot;">​</a></h3><p>一个人的语言系统，就代表他的人生。语言是思维的外显，思维决定行为，行为决定结果。改变命运，从优化语言系统开始。</p><p><strong>关键论点：</strong></p><ul><li>人的语言系统决定命运走向</li><li>会说话的人，可以少奋斗30年</li><li>一开口就是价值，一聊天就是收钱</li></ul><h3 id="_2-好好说话是保护自己" tabindex="-1">2. 好好说话是保护自己 <a class="header-anchor" href="#_2-好好说话是保护自己" aria-label="Permalink to &quot;2. 好好说话是保护自己&quot;">​</a></h3><p>说话的本质不是为了表达情绪，而是为了链接，为了达成合作。好好说话是保护自己，不给人伤害自己的机会。</p><p><strong>关键论点：</strong></p><ul><li>说话是为了链接系统，越说话朋友越多</li><li>说话考虑对方的感受，可以避开人生一半的麻烦</li><li>做事考虑对方的利益，可以避开另外50%的麻烦</li></ul><h3 id="_3-满足人的精神需求" tabindex="-1">3. 满足人的精神需求 <a class="header-anchor" href="#_3-满足人的精神需求" aria-label="Permalink to &quot;3. 满足人的精神需求&quot;">​</a></h3><p>满足人的精神需求，就是满足人的劣根性。人的劣根性包括：</p><ul><li>主观性（别人都错了，你对了）</li><li>虚荣心（喜欢甜言蜜语）</li><li>奴性（遇到有权有钱的人便点头哈腰）</li><li>贪得无厌（既要又要还要）</li><li>傲慢（鼓励穷人一夜暴富）</li><li>懒惰（各种自动赚钱神器）</li><li>急功近利（每天2小时月入100W+）</li></ul><h3 id="_4-套话是牛人的护身符" tabindex="-1">4. 套话是牛人的护身符 <a class="header-anchor" href="#_4-套话是牛人的护身符" aria-label="Permalink to &quot;4. 套话是牛人的护身符&quot;">​</a></h3><p>真正有价值的话，多是套话，多是家常话。一个人开始说套话，多是混出来了，或者因为不会说话，付出过代价。套话不是忽悠，是人类智慧的最高峰。</p><h3 id="_5-说话的底线与禁区" tabindex="-1">5. 说话的底线与禁区 <a class="header-anchor" href="#_5-说话的底线与禁区" aria-label="Permalink to &quot;5. 说话的底线与禁区&quot;">​</a></h3><p><strong>必须养成的习惯：</strong></p><ul><li>习惯性表达善意</li><li>习惯性表达感恩</li><li>习惯性给人抬轿子</li><li>习惯性循环正面积极的语言</li><li>少解释、少争论、少劝说</li><li>说关键、长话短说、想清楚再说</li></ul><p><strong>永远的禁区：</strong></p><ul><li>永不抬杠、永不怼人、永不白嫖</li><li>永不抱怨、永不借钱、永不占小便宜</li><li>永不恶语伤人、永不诋毁他人</li><li>永远不要试探人、打听别人隐私</li><li>永远不要把别人当成傻逼</li><li>永远不要过度解释、说废话、说闲话</li></ul><hr><h2 id="二、启发思考" tabindex="-1">二、启发思考 <a class="header-anchor" href="#二、启发思考" aria-label="Permalink to &quot;二、启发思考&quot;">​</a></h2><h3 id="人生发展维度" tabindex="-1">人生发展维度 <a class="header-anchor" href="#人生发展维度" aria-label="Permalink to &quot;人生发展维度&quot;">​</a></h3><p><strong>启发1：无欲则刚</strong></p><p>什么叫无欲则刚？有人说他想日赚1个亿，支持他；有人说他想死，支持他。听什么样的话，都顺耳了。自己的梦想是什么，每天说个100遍1000遍，大家听多了，习以为常，见怪不怪。活着，不要脸才是王道。</p><p><strong>启发2：神一样的语言</strong></p><p>具备神一样的思维，就会具备神一样的语言。老和尚一说话，就是循环金刚经；老流氓一说话，就是循环商君书；老狐狸一说话，就是循环厚黑学。读书改变命运，知行合一，就能吃掉芸芸众生。</p><p><strong>启发3：老实人是最智慧的</strong></p><p>老实不是不分场合乱说话，不是随便透露别人隐私。老实是敬畏——敬畏无形的力量、敬畏未知的事物、敬畏因果报应。一个人能当老实人，说明他非常有智慧。至诚如神。</p><h3 id="家庭关系维度" tabindex="-1">家庭关系维度 <a class="header-anchor" href="#家庭关系维度" aria-label="Permalink to &quot;家庭关系维度&quot;">​</a></h3><p><strong>启发1：就一个原则：什么都听媳妇的</strong></p><p>家里听话的人，不累。说话的人，操心多，则累。世上最轻松的活，就是听话。改变命运，从听媳妇的话开始。对媳妇好，则家庭旺；反之，则多灾多难。</p><p><strong>启发2：孝顺的本质</strong></p><p>什么叫孝顺父母？就是能顺着父母的事儿，就顺着父母。有些事儿，不方便顺着父母，就找几个能量高的人劝劝父母，以和为贵。家和万事兴。</p><p><strong>启发3：兄弟姐妹相处之道</strong></p><p>兄弟姐妹之间怎么沟通不重要，重要的是彼此不借钱，或彼此借钱了会还。小常识：姐姐从弟弟那儿拿钱一般不还，弟弟从哥哥那儿拿钱一般不还，小舅子从姐夫那儿拿钱一般不还。</p><h3 id="事业发展维度" tabindex="-1">事业发展维度 <a class="header-anchor" href="#事业发展维度" aria-label="Permalink to &quot;事业发展维度&quot;">​</a></h3><p><strong>启发1：说话是为了发家致富</strong></p><p>说话是为了发家致富，升官发财，合法吃掉更多资源。不是说你油腔滑调就能改变命运，好好说话是有成本的，是你愿意承担什么风险。</p><p><strong>启发2：和气生财的秘密</strong></p><p>人的运气要败的时候，是从气上先败的。一个家庭很和乐很温馨，一定兴旺。要是人人说话尖酸刻薄，像下冰雹一样，心一寒，想笑都笑不出来。久之，就成了苦瓜相，做生意客户见了都害怕，财运就消失了。</p><p><strong>启发3：帮弱势群体说话但不帮他们解决问题</strong></p><p>赚钱的秘密是什么？帮弱势群体说话，但不帮他们解决问题。弱势群体都是鼠目寸光，不要跟他们强调长远利益，就说当下能得到什么就行。</p><h3 id="小孩子教育维度" tabindex="-1">小孩子教育维度 <a class="header-anchor" href="#小孩子教育维度" aria-label="Permalink to &quot;小孩子教育维度&quot;">​</a></h3><p><strong>启发1：说话是童子功</strong></p><p>说话是一个童子功。小孩的语言打磨出来了，长大一说话就是链接宇宙万物。聪明的孩子会习惯性说：我对不起老师，我对不起爸爸妈妈。一个对不起就把老师和爸爸妈妈链接起来了。</p><p><strong>启发2：怎么教小孩好好说话</strong></p><p>告诉他第一步该怎么做，第二步该怎么做，第三步该怎么做。他做个动作，习惯性鼓励他一下就行。或者问他的想法是什么，帮他把想法变成具体的执行方案即可。</p><p><strong>启发3：避免开放式提问</strong></p><p>开放式提问=自讨苦吃，会激发客户的恶。封闭式提问=过滤垃圾流量，会激发客户的善。比如：做一个善良的人好还是不好？说老板的坏话好还是不好？</p><hr><h2 id="三、专属建议-结合个人背景" tabindex="-1">三、专属建议（结合个人背景） <a class="header-anchor" href="#三、专属建议-结合个人背景" aria-label="Permalink to &quot;三、专属建议（结合个人背景）&quot;">​</a></h2><blockquote><p>个人背景：17年软件开发经验，技术总监/项目管理/部门经理，带过20+人项目和30+人部门，两个孩子父亲，因家庭和个人身体精力原因想了解其他行业或寻求改变</p></blockquote><h3 id="针对技术管理者的转型建议" tabindex="-1">针对技术管理者的转型建议 <a class="header-anchor" href="#针对技术管理者的转型建议" aria-label="Permalink to &quot;针对技术管理者的转型建议&quot;">​</a></h3><p><strong>建议1：学会说套话</strong></p><p>作为技术管理者，习惯了直接、精确的技术语言。但在商务和管理层面，要学会说套话。套话是牛人的护身符，不是忽悠，是智慧的体现。遇到职场转型，学会说&quot;我会考虑一下&quot;、&quot;事在人为&quot;这类话，给自己留余地。</p><p><strong>建议2：说话要软，做事要硬</strong></p><p>技术人容易说话太真伤己。书中说：说话太直伤人，说话太真伤己。转型过程中，学会说话习惯性过脑子，把直话拐个弯说，多说有温度的话，冷冰冰的话加热了说。</p><p><strong>建议3：习惯性服软</strong></p><p>就没有服软3次解决不了的问题。转型过程中会遇到阻力，习惯示弱低头服软。比如：我没你经济能力强，也没你厉害。这些年，都是你在支撑着，不然我们早喝西北风了。</p><h3 id="针对项目管理者的沟通建议" tabindex="-1">针对项目管理者的沟通建议 <a class="header-anchor" href="#针对项目管理者的沟通建议" aria-label="Permalink to &quot;针对项目管理者的沟通建议&quot;">​</a></h3><p><strong>建议1：管理员工的具体方法</strong></p><p>让他干什么，你说明白。你想要什么结果，也说明白。说的时候，一定要尊重人家。礼贤下士，员工的积极性才能淋漓尽致发挥出来。老板用员工，就是让他们做一些重复的事儿。</p><p><strong>建议2：应对闯祸员工的话术</strong></p><p>人犯错了，都不想改，因为不就证明他是错的吗？员工犯错时：这样的事儿以后如何才能避免，你能出个方案吗？而不是你好好反省一下。</p><p><strong>建议3：激励员工的艺术</strong></p><p>你一定能搞定的，第一步你要这么做，第二步你要这么做，第三步你要这么做。是不是现在思路清晰多了？而不是你怎么啥都不懂啊。</p><h3 id="针对父亲角色的建议" tabindex="-1">针对父亲角色的建议 <a class="header-anchor" href="#针对父亲角色的建议" aria-label="Permalink to &quot;针对父亲角色的建议&quot;">​</a></h3><p><strong>建议1：教育孩子的核心</strong></p><p>说话是童子功。培养孩子会说话的习惯：多用123结构表达观点，习惯性总结，习惯性表达善意和感恩。</p><p><strong>建议2：避免命令式语言</strong></p><p>说话不带把，非富即贵。习惯性把命令一类的句子转化成祈使句。&quot;把门关上&quot;变成&quot;关上门好吗？&quot;让孩子感受到尊重和商量。</p><p><strong>建议3：与孩子沟通的技巧</strong></p><p>你一定能搞定的，你说说现在打算怎么做？而不是你怎么连这点东西都搞不明白。让孩子学会自我表达和规划。</p><h3 id="针对身体精力问题的建议" tabindex="-1">针对身体精力问题的建议 <a class="header-anchor" href="#针对身体精力问题的建议" aria-label="Permalink to &quot;针对身体精力问题的建议&quot;">​</a></h3><p><strong>建议1：减少说话消耗</strong></p><p>修为越高的人，越不会多说话。说话是一门艺术，不说话则是一种修行。身体精力有限时，学会减少无效沟通，把精力用在关键节点。</p><p><strong>建议2：情绪管理</strong></p><p>生气的时候不要说话。气话、牢骚话写在纸上然后烧了。不要仗着被爱，就随便对亲近的人发火。</p><hr><h2 id="四、行动计划" tabindex="-1">四、行动计划 <a class="header-anchor" href="#四、行动计划" aria-label="Permalink to &quot;四、行动计划&quot;">​</a></h2><h3 id="人生发展行动项" tabindex="-1">人生发展行动项 <a class="header-anchor" href="#人生发展行动项" aria-label="Permalink to &quot;人生发展行动项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>时间节点</th><th>备注</th></tr></thead><tbody><tr><td>1</td><td>每天对着镜子练习微笑点头</td><td>每天5分钟</td><td>说话的态度就修出来了</td></tr><tr><td>2</td><td>习惯性录音自己说的话</td><td>每天晚上复盘</td><td>在众目睽睽之下能放吗？不能就灭了</td></tr><tr><td>3</td><td>阅读《资治通鉴》和《史记》</td><td>每周3小时</td><td>优化语言结构</td></tr><tr><td>4</td><td>看牛人演讲视频和访谈</td><td>每周2小时</td><td>学习史玉柱、段永平的表达</td></tr></tbody></table><h3 id="家庭关系行动项" tabindex="-1">家庭关系行动项 <a class="header-anchor" href="#家庭关系行动项" aria-label="Permalink to &quot;家庭关系行动项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>时间节点</th><th>备注</th></tr></thead><tbody><tr><td>1</td><td>家里多放几面镜子</td><td>本周完成</td><td>人就会习惯性谦卑</td></tr><tr><td>2</td><td>跟媳妇一起听录音复盘</td><td>每周一次</td><td>这个录音能在众目睽睽下放吗？</td></tr><tr><td>3</td><td>什么都听媳妇的</td><td>即刻执行</td><td>改变家族命运从听媳妇话开始</td></tr><tr><td>4</td><td>能顺着父母的事儿就顺着</td><td>即刻执行</td><td>家和万事兴</td></tr></tbody></table><h3 id="事业发展行动项" tabindex="-1">事业发展行动项 <a class="header-anchor" href="#事业发展行动项" aria-label="Permalink to &quot;事业发展行动项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>时间节点</th><th>备注</th></tr></thead><tbody><tr><td>1</td><td>收集365句优化后的语言</td><td>每天一句</td><td>一天说一句，这辈子遇不到竞争对手</td></tr><tr><td>2</td><td>只聊自己专业以内的话</td><td>即刻执行</td><td>超过自己专业的话，不说</td></tr><tr><td>3</td><td>习惯性用123表达观点</td><td>即刻执行</td><td>没人喜欢听长篇大论</td></tr><tr><td>4</td><td>二八定律：夸奖和意见比例2:8</td><td>即刻执行</td><td>这是让对方最容易接受的方式</td></tr></tbody></table><h3 id="小孩子教育行动项" tabindex="-1">小孩子教育行动项 <a class="header-anchor" href="#小孩子教育行动项" aria-label="Permalink to &quot;小孩子教育行动项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>行动项</th><th>时间节点</th><th>备注</th></tr></thead><tbody><tr><td>1</td><td>教孩子用123结构表达</td><td>每天练习</td><td>说话养成总结的习惯</td></tr><tr><td>2</td><td>把命令转化成祈使句</td><td>即刻执行</td><td>&quot;把门关上&quot;→&quot;关上门好吗？&quot;</td></tr><tr><td>3</td><td>遇到问题问孩子：你打算怎么做</td><td>即刻执行</td><td>培养孩子的规划能力</td></tr><tr><td>4</td><td>每天鼓励孩子一次</td><td>即刻执行</td><td>帮他把想法变成执行方案</td></tr></tbody></table><hr><h2 id="五、关键话术速查表" tabindex="-1">五、关键话术速查表 <a class="header-anchor" href="#五、关键话术速查表" aria-label="Permalink to &quot;五、关键话术速查表&quot;">​</a></h2><h3 id="日常沟通话术对照" tabindex="-1">日常沟通话术对照 <a class="header-anchor" href="#日常沟通话术对照" aria-label="Permalink to &quot;日常沟通话术对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>不好的说法</th><th>好的说法</th></tr></thead><tbody><tr><td>您最近是不是很累？</td><td>您最近过得挺好吧？</td></tr><tr><td>您真不容易啊</td><td>您太牛了，太有毅力了</td></tr><tr><td>您听明白了吗？</td><td>我说清楚了吗？</td></tr><tr><td>你一直没回复我</td><td>我一直在等您回复呢，哈哈</td></tr><tr><td>您今年多大？</td><td>您是几零后？</td></tr><tr><td>你还记得我吗？</td><td>我是上次在XX跟您见过面的XX</td></tr><tr><td>改天一起吃饭</td><td>周五晚上有空吗？</td></tr><tr><td>知道了</td><td>我明白您的意思了，您看是不是这样？</td></tr></tbody></table><h3 id="职场沟通话术对照" tabindex="-1">职场沟通话术对照 <a class="header-anchor" href="#职场沟通话术对照" aria-label="Permalink to &quot;职场沟通话术对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>不好的说法</th><th>好的说法</th></tr></thead><tbody><tr><td>这个活不归我干啊</td><td>对不起，能缓缓吗？今天我去不了了</td></tr><tr><td>我不可能加班</td><td>18点之前我接孩子，实在抱歉不能一起冲锋陷阵了</td></tr><tr><td>这件事你怎么不早说？</td><td>这事儿是我没有尽早跟您确认，失误失误</td></tr><tr><td>我日你娘！</td><td>能不能告诉我怎么才能把这件事弄得更好吗？</td></tr><tr><td>你是蠢猪吗？</td><td>XX页的1、2、3点一定要多看几遍！</td></tr><tr><td>你上班挺悠闲的</td><td>不管别人怎么说，你都能完成工作</td></tr><tr><td>希望你识趣点主动辞职</td><td>我认为你在这儿屈才了，外面有更好的机会可以留意</td></tr></tbody></table><h3 id="家庭沟通话术对照" tabindex="-1">家庭沟通话术对照 <a class="header-anchor" href="#家庭沟通话术对照" aria-label="Permalink to &quot;家庭沟通话术对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>不好的说法</th><th>好的说法</th></tr></thead><tbody><tr><td>家里的碗不是一直都是你洗的吗？</td><td>老婆，碗洗好了，衣服晾了，地板还要拖一拖吗？</td></tr><tr><td>你这个老古董什么都不懂</td><td>您年纪越大越有智慧了，我真佩服您！</td></tr><tr><td>你把这个家搞得乌烟瘴气</td><td>您就是我们心中的活菩萨，功德无量</td></tr></tbody></table><h3 id="客户沟通话术对照" tabindex="-1">客户沟通话术对照 <a class="header-anchor" href="#客户沟通话术对照" aria-label="Permalink to &quot;客户沟通话术对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>不好的说法</th><th>好的说法</th></tr></thead><tbody><tr><td>请你给我钱</td><td>谢谢您认可我，请问您是用微信还是支付宝付款？</td></tr><tr><td>跟你聊天很开心</td><td>跟您聊天激活了我的智慧，感谢您加持了我</td></tr><tr><td>味道还可以</td><td>确实好吃，666！</td></tr><tr><td>这家店越来越垃圾了</td><td>我进化比较慢，还是怀念以前的味道</td></tr><tr><td>我太忙了去不了</td><td>现在我实在抽不出时间，X月X日我负荆请罪</td></tr></tbody></table><hr><h2 id="六、读书感悟" tabindex="-1">六、读书感悟 <a class="header-anchor" href="#六、读书感悟" aria-label="Permalink to &quot;六、读书感悟&quot;">​</a></h2><p>这本书的核心思想可以用一句话概括：<strong>语言系统决定命运，好好说话是保护自己。</strong></p><p>对于有17年技术背景的我来说，这本书最大的冲击是：技术思维和商务思维的语言系统完全不同。技术追求精确、直接、效率；商务追求模糊、委婉、链接。转型过程中，需要刻意训练新的语言系统。</p><p>书中反复强调的&quot;套话是牛人的护身符&quot;这一观点，让我重新审视了所谓&quot;油腔滑调&quot;的价值。套话不是虚伪，是智慧，是给自己留余地，是不说错话的保障。</p><p>关于家庭关系，&quot;什么都听媳妇的&quot;这一原则看似简单，实则蕴含深意。听话的人不累，说话的人操心多。家庭和谐从学会听话开始。</p><p>关于孩子教育，&quot;说话是童子功&quot;这一观点让我意识到，培养孩子的语言能力是贯穿一生的重要投资。不是教知识，而是教表达、教链接、教感恩。</p><p>最后，书中的一个观点值得终身铭记：<strong>夸人永远都是对的。人可以防御他人的攻击，但对他人的赞美毫无抵抗力。进攻一个人最好的方式就是夸奖他。</strong></p><hr><h2 id="七、延伸阅读建议" tabindex="-1">七、延伸阅读建议 <a class="header-anchor" href="#七、延伸阅读建议" aria-label="Permalink to &quot;七、延伸阅读建议&quot;">​</a></h2><ol><li>《资治通鉴》- 优化语言结构，学习古人智慧</li><li>《史记》- 理解人性，掌握说话之道</li><li>《段永平访谈录》- 学习牛人说话方式</li><li>《商君书》- 理解权力逻辑</li><li>《厚黑学》- 理解职场潜规则</li><li>《金刚经》- 理解宗教语言之美</li></ol><hr><p><em>笔记整理于2026年7月13日</em></p>',114)])])}const q=d(o,[["render",l]]);export{u as __pageData,q as default};
